          end\n            else\n                relative_parsed.path = absolute_path(base_parsed.path or \"\",\n                    relative_parsed.path)\n            end\n        end\n        result = _M.build(relative_parsed)\n    end\n    return remove_dot_components(result)\nend\n\n-----------------------------------------------------------------------------\n-- Breaks a path into its segments, unescaping the segments\n-- Input\n--   path\n-- Returns\n--   segment: a table with one entry per segment\n-----------------------------------------------------------------------------\nfunction _M.parse_path(path)\n    local parsed = {}\n    path = path or \"\"\n    --path = string.gsub(path, \"%s\", \"\")\n    string.gsub(path, \"([^/]+)\", function (s) table.insert(parsed, s) end)\n    for i = 1, #parsed do\n        parsed[i] = _M.unescape(parsed[i])\n    end\n    if string.sub(path, 1, 1) == \"/\" then parsed.is_absolute = 1 end\n    if string.sub(path, -1, -1) == \"/\" then parsed.is_directory = 1 end\n    return parsed\nend\n\n-----------------------------------------------------------------------------\n-- Builds a path component from its segments, escaping protected characters.\n-- Input\n--   parsed: path segments\n--   unsafe: if true, segments are not protected before path is built\n-- Returns\n--   path: corresponding path stringing\n-----------------------------------------------------------------------------\nfunction _M.build_path(parsed, unsafe)\n    local path = \"\"\n    local n = #parsed\n    if unsafe then\n        for i = 1, n-1 do\n            path = path .. parsed[i]\n            path = path .. \"/\"\n        end\n        if n > 0 then\n            path = path .. parsed[n]\n            if parsed.is_directory then path = path .. \"/\" end\n        end\n    else\n        for i = 1, n-1 do\n            path = path .. protect_segment(parsed[i])\n            path = path .. \"/\"\n        end\n        if n > 0 then\n            path = path .. protect_segment(parsed[n])\n            if parsed.is_directory then path = path .. \"/\" end\n        end\n    end\n    if parsed.is_absolute then path = \"/\" .. path end\n    return path\nend\n\nreturn _M\n", "@socket.url")
package.preload["socket.tp"] = load("-----------------------------------------------------------------------------\n-- Unified SMTP/FTP subsystem\n-- LuaSocket toolkit.\n-- Author: Diego Nehab\n-----------------------------------------------------------------------------\n\n-----------------------------------------------------------------------------\n-- Declare module and import dependencies\n-----------------------------------------------------------------------------\nlocal base = _G\nlocal string = require(\"string\")\nlocal socket = require(\"socket\")\nlocal ltn12 = require(\"ltn12\")\n\nsocket.tp = {}\nlocal _M = socket.tp\n\n-----------------------------------------------------------------------------\n-- Program constants\n-----------------------------------------------------------------------------\n_M.TIMEOUT = 60\n\n-----------------------------------------------------------------------------\n-- Implementation\n-----------------------------------------------------------------------------\n-- gets server reply (works for SMTP and FTP)\nlocal function get_reply(c)\n    local code, current, sep\n    local line, err = c:receive()\n    local reply = line\n    if err then return nil, err end\n    code, sep = socket.skip(2, string.find(line, \"^(%d%d%d)(.?)\"))\n    if not code then return nil, \"invalid server reply\" end\n    if sep == \"-\" then -- reply is multiline\n        repeat\n            line, err = c:receive()\n            if err then return nil, err end\n            current, sep = socket.skip(2, string.find(line, \"^(%d%d%d)(.?)\"))\n            reply = reply .. \"\\n\" .. line\n        -- reply ends with same code\n        until code == current and sep == \" \"\n    end\n    return code, reply\nend\n\n-- metatable for sock object\nlocal metat = { __index = {} }\n\nfunction metat.__index:getpeername()\n    return self.c:getpeername()\nend\n\nfunction metat.__index:getsockname()\n    return self.c:getpeername()\nend\n\nfunction metat.__index:check(ok)\n    local code, reply = get_reply(self.c)\n    if not code then return nil, reply end\n    if base.type(ok) ~= \"function\" then\n        if base.type(ok) == \"table\" then\n            for i, v in base.ipairs(ok) do\n                if string.find(code, v) then\n                    return base.tonumber(code), reply\n                end\n            end\n            return nil, reply\n        else\n            if string.find(code, ok) then return base.tonumber(code), reply\n            else return nil, reply end\n        end\n    else return ok(base.tonumber(code), reply) end\nend\n\nfunction metat.__index:command(cmd, arg)\n    cmd = string.upper(cmd)\n    if arg then\n        return self.c:send(cmd .. \" \" .. arg.. \"\\r\\n\")\n    else\n        return self.c:send(cmd .. \"\\r\\n\")\n    end\nend\n\nfunction metat.__index:sink(snk, pat)\n    local chunk, err = self.c:receive(pat)\n    return snk(chunk, err)\nend\n\nfunction metat.__index:send(data)\n    return self.c:send(data)\nend\n\nfunction metat.__index:receive(pat)\n    return self.c:receive(pat)\nend\n\nfunction metat.__index:getfd()\n    return self.c:getfd()\nend\n\nfunction metat.__index:dirty()\n    return self.c:dirty()\nend\n\nfunction metat.__index:getcontrol()\n    return self.c\nend\n\nfunction metat.__index:source(source, step)\n    local sink = socket.sink(\"keep-open\", self.c)\n    local ret, err = ltn12.pump.all(source, sink, step or ltn12.pump.step)\n    return ret, err\nend\n\n-- closes the underlying c\nfunction metat.__index:close()\n    self.c:close()\n    return 1\nend\n\n-- connect with server and return c object\nfunction _M.connect(host, port, timeout, create)\n    local c, e = (create or socket.tcp)()\n    if not c then return nil, e end\n    c:settimeout(timeout or _M.TIMEOUT)\n    local r, e = c:connect(host, port)\n    if not r then\n        c:close()\n        return nil, e\n    end\n    return base.setmetatable({c = c}, metat)\nend\n\nreturn _M\n", "@socket.tp")
