package.preload["pl.operator"] = load("--- Lua operators available as functions.\n--\n-- (similar to the Python module of the same name)\n--\n-- There is a module field `optable` which maps the operator strings\n-- onto these functions, e.g. `operator.optable['()']==operator.call`\n--\n-- Operator strings like '>' and '{}' can be passed to most Penlight functions\n-- expecting a function argument.\n--\n-- @module pl.operator\n\nlocal strfind = string.find\n\nlocal operator = {}\n\n--- apply function to some arguments **()**\n-- @param fn a function or callable object\n-- @param ... arguments\nfunction operator.call(fn,...)\n    return fn(...)\nend\n\n--- get the indexed value from a table **[]**\n-- @param t a table or any indexable object\n-- @param k the key\nfunction  operator.index(t,k)\n    return t[k]\nend\n\n--- returns true if arguments are equal **==**\n-- @param a value\n-- @param b value\nfunction  operator.eq(a,b)\n    return a==b\nend\n\n--- returns true if arguments are not equal **~=**\n -- @param a value\n-- @param b value\nfunction  operator.neq(a,b)\n    return a~=b\nend\n\n--- returns true if a is less than b **<**\n-- @param a value\n-- @param b value\nfunction  operator.lt(a,b)\n    return a < b\nend\n\n--- returns true if a is less or equal to b **<=**\n-- @param a value\n-- @param b value\nfunction  operator.le(a,b)\n    return a <= b\nend\n\n--- returns true if a is greater than b **>**\n-- @param a value\n-- @param b value\nfunction  operator.gt(a,b)\n    return a > b\nend\n\n--- returns true if a is greater or equal to b **>=**\n-- @param a value\n-- @param b value\nfunction  operator.ge(a,b)\n    return a >= b\nend\n\n--- returns length of string or table **#**\n-- @param a a string or a table\nfunction  operator.len(a)\n    return #a\nend\n\n--- add two values **+**\n-- @param a value\n-- @param b value\nfunction  operator.add(a,b)\n    return a+b\nend\n\n--- subtract b from a **-**\n-- @param a value\n-- @param b value\nfunction  operator.sub(a,b)\n    return a-b\nend\n\n--- multiply two values __*__\n-- @param a value\n-- @param b value\nfunction  operator.mul(a,b)\n    return a*b\nend\n\n--- divide first value by second **/**\n-- @param a value\n-- @param b value\nfunction  operator.div(a,b)\n    return a/b\nend\n\n--- raise first to the power of second **^**\n-- @param a value\n-- @param b value\nfunction  operator.pow(a,b)\n    return a^b\nend\n\n--- modulo; remainder of a divided by b **%**\n-- @param a value\n-- @param b value\nfunction  operator.mod(a,b)\n    return a%b\nend\n\n--- concatenate two values (either strings or `__concat` defined) **..**\n-- @param a value\n-- @param b value\nfunction  operator.concat(a,b)\n    return a..b\nend\n\n--- return the negative of a value **-**\n-- @param a value\nfunction  operator.unm(a)\n    return -a\nend\n\n--- false if value evaluates as true **not**\n-- @param a value\nfunction  operator.lnot(a)\n    return not a\nend\n\n--- true if both values evaluate as true **and**\n-- @param a value\n-- @param b value\nfunction  operator.land(a,b)\n    return a and b\nend\n\n--- true if either value evaluate as true **or**\n-- @param a value\n-- @param b value\nfunction  operator.lor(a,b)\n    return a or b\nend\n\n--- make a table from the arguments **{}**\n-- @param ... non-nil arguments\n-- @return a table\nfunction  operator.table (...)\n    return {...}\nend\n\n--- match two strings **~**.\n-- uses @{string.find}\nfunction  operator.match (a,b)\n    return strfind(a,b)~=nil\nend\n\n--- the null operation.\n-- @param ... arguments\n-- @return the arguments\nfunction  operator.nop (...)\n    return ...\nend\n\n---- Map from operator symbol to function.\n-- Most of these map directly from operators;\n-- But note these extras\n--\n--  * __'()'__  `call`\n--  * __'[]'__  `index`\n--  * __'{}'__ `table`\n--  * __'~'__   `match`\n--\n-- @table optable\n-- @field operator\n operator.optable = {\n    ['+']=operator.add,\n    ['-']=operator.sub,\n    ['*']=operator.mul,\n    ['/']=operator.div,\n    ['%']=operator.mod,\n    ['^']=operator.pow,\n    ['..']=operator.concat,\n    ['()']=operator.call,\n    ['[]']=operator.index,\n    ['<']=operator.lt,\n    ['<=']=operator.le,\n    ['>']=operator.gt,\n    ['>=']=operator.ge,\n    ['==']=operator.eq,\n    ['~=']=operator.neq,\n    ['#']=operator.len,\n    ['and']=operator.land,\n    ['or']=operator.lor,\n    ['{}']=operator.table,\n    ['~']=operator.match,\n    ['']=operator.nop,\n}\n\nreturn operator\n", "@pl.operator")
package.preload["luacov.hook"] = load("------------------------\n-- Hook module, creates debug hook used by LuaCov.\n-- @class module\n-- @name luacov.hook\nlocal hook = {}\n\n----------------------------------------------------------------\nlocal dir_sep = package.config:sub(1, 1)\nif not dir_sep:find(\"[/\\\\]\") then\n   dir_sep = \"/\"\nend\n\n--- Creates a new debug hook.\n-- @param runner runner module.\n-- @return debug hook function that uses runner fields and functions\n-- and sets `runner.data`.\nfunction hook.new(runner)\n   local ignored_files = {}\n   local steps_after_save = 0\n\n   return function(_, line_nr, level)\n      -- Do not use string metamethods within the debug hook:\n      -- they may be absent if it's called from a sandboxed environment\n      -- or because of carelessly implemented monkey-patching.\n      level = level or 2\n      if not runner.initialized then\n         return\n      end\n\n      -- Get name of processed file.\n      local name = debug.getinfo(level, \"S\").source\n      local prefixed_name = string.match(name, \"^@(.*)\")\n      if prefixed_name then\n         name = prefixed_name:gsub(\"^%.[/\\\\]\", \"\"):gsub(\"[/\\\\]\", dir_sep)\n      elseif not runner.configuration.codefromstrings then\n         -- Ignore Lua code loaded from raw strings by default.\n         return\n      end\n\n      local data = runner.data\n      local file = data[name]\n\n      if not file then\n         -- New or ignored file.\n         if ignored_files[name] then\n            return\n         elseif runner.file_included(name) then\n            file = {max = 0, max_hits = 0}\n            data[name] = file\n         else\n            ignored_files[name] = true\n            return\n         end\n      end\n\n      if line_nr > file.max then\n         file.max = line_nr\n      end\n\n      local hits = (file[line_nr] or 0) + 1\n      file[line_nr] = hits\n\n      if hits > file.max_hits then\n         file.max_hits = hits\n      end\n\n      if runner.tick then\n         steps_after_save = steps_after_save + 1\n\n         if steps_after_save == runner.configuration.savestepsize then\n            steps_after_save = 0\n\n            if not runner.paused then\n               runner.save_stats()\n            end\n         end\n      end\n   end\nend\n\nreturn hook\n", "@luacov.hook")
package.preload["pl.lexer"] = load("--- Lexical scanner for creating a sequence of tokens from text.\n-- `lexer.scan(s)` returns an iterator over all tokens found in the\n-- string `s`. This iterator returns two values, a token type string\n-- (such as 'string' for quoted string, 'iden' for identifier) and the value of the\n-- token.\n--\n-- Versions specialized for Lua and C are available; these also handle block comments\n-- and classify keywords as 'keyword' tokens. For example:\n--\n--    > s = 'for i=1,n do'\n--    > for t,v in lexer.lua(s)  do print(t,v) end\n--    keyword for\n--    iden    i\n--    =       =\n--    number  1\n--    ,       ,\n--    iden    n\n--    keyword do\n--\n-- See the Guide for further @{06-data.md.Lexical_Scanning|discussion}\n-- @module pl.lexer\n\nlocal strfind = string.find\nlocal strsub = string.sub\nlocal append = table.insert\n\n\nlocal function assert_arg(idx,val,tp)\n    if type(val) ~= tp then\n        error(\"argument \"..idx..\" must be \"..tp, 2)\n    end\nend\n\nlocal lexer = {}\n\nlocal NUMBER1  = '^[%+%-]?%d+%.?%d*[eE][%+%-]?%d+'\nlocal NUMBER1a = '^[%+%-]?%d*%.%d+[eE][%+%-]?%d+'\nlocal NUMBER2  = '^[%+%-]?%d+%.?%d*'\nlocal NUMBER2a = '^[%+%-]?%d*%.%d+'\nlocal NUMBER3  = '^0x[%da-fA-F]+'\nlocal NUMBER4  = '^%d+%.?%d*[eE][%+%-]?%d+'\nlocal NUMBER4a = '^%d*%.%d+[eE][%+%-]?%d+'\nlocal NUMBER5  = '^%d+%.?%d*'\nlocal NUMBER5a = '^%d*%.%d+'\nlocal IDEN = '^[%a_][%w_]*'\nlocal WSPACE = '^%s+'\nlocal STRING1 = \"^(['\\\"])%1\" -- empty string\nlocal STRING2 = [[^(['\"])(\\*)%2%1]]\nlocal STRING3 = [[^(['\"]).-[^\\](\\*)%2%1]]\nlocal CHAR1 = \"^''\"\nlocal CHAR2 = [[^'(\\*)%1']]\nlocal CHAR3 = [[^'.-[^\\](\\*)%1']]\nlocal PREPRO = '^#.-[^\\\\]\\n'\n\nlocal plain_matches,lua_matches,cpp_matches,lua_keyword,cpp_keyword\n\nlocal function tdump(tok)\n    return tok,tok\nend\n\nlocal function ndump(tok,options)\n    if options and options.number then\n        tok = tonumber(tok)\n    end\n    return \"number\",tok\nend\n\n-- regular